            . "<div class='section'><h2>Detalle de alertas</h2>{$detailBlocks}</div>"
            . "<div class='footer'><p><strong>Reporte generado automáticamente</strong></p>"
            . "<p>{$reportData['generated_at']} — Sistema de Control de Asistencia · Datos de hhempeos_calidad</p></div>"
            . "</div></body></html>";
    }
}

if (!function_exists('sendQualityAlertsReportByEmail')) {
    function sendQualityAlertsReportByEmail(PDO $pdo, array $reportData, array $recipients, string $aiSummary = ''): bool
    {
        if (empty($recipients)) {
            error_log('[quality_alerts_report] No recipients configured');
            return false;
        }

        $html = generateQualityAlertsReportHTML($reportData, $aiSummary);
        require_once __DIR__ . '/email_functions.php';

        $result = sendDailyQualityAlertsReport($html, $recipients, $reportData);

        if ($result['success']) {
            error_log('[quality_alerts_report] Sent: ' . $result['message']);
            return true;
        }
        error_log('[quality_alerts_report] Failed: ' . $result['message']);
        return false;
    }
}
